import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { useDropzone } from "react-dropzone";
import {
  getProduct,
  updateAProduct,
  resetState,
} from "../features/product/productSlice";
import { uploadImg, delImg } from "../features/upload/uploadSlice";
import { getCategories } from "../features/pcategory/pcategorySlice";
import { getBrands } from "../features/brand/brandSlice";

import {
  Button,
  Form,
  Input,
  InputNumber,
  Select,
  Spin,
  Tag,
  Tooltip,
  Divider,
} from "antd";
import {
  Package,
  Save,
  ArrowLeft,
  Layers,
  Layout,
  Image as ImageIcon,
  Upload,
  X,
  CheckCircle2,
  Zap,
  Tag as TagIcon,
  ShoppingBag,
  DollarSign,
  Box,
  Plus,
  AlertCircle,
  Stethoscope,
  Activity,
  ShieldCheck,
  Cpu
} from "lucide-react";
import ReactQuill from "react-quill";
import "react-quill/dist/quill.snow.css";

const EditProducts = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const [form] = Form.useForm();

  const [productImages, setProductImages] = useState([]);

  const {
    selectedProduct,
    isLoading,
    isSuccess,
    isError,
    message: productMessage,
  } = useSelector((state) => state.product);
  const categoryState = useSelector((state) => state.pCategory.pCategories);
  const brandState = useSelector((state) => state.brand.brands);
  const imgState = useSelector((state) => state.upload.images);
  const uploadLoading = useSelector((state) => state.upload.isLoading);

  useEffect(() => {
    if (id) {
      dispatch(getProduct(id));
      dispatch(getCategories());
      dispatch(getBrands());
    }
  }, [dispatch, id]);

  useEffect(() => {
    if (selectedProduct) {
      form.setFieldsValue({
        title: selectedProduct.title,
        description: selectedProduct.description,
        price: selectedProduct.price,
        brand: selectedProduct.brand,
        quantity: selectedProduct.quantity,
        category: selectedProduct.category,
        tags: selectedProduct.tags,
      });
      const existingImages =
        selectedProduct.images ||
        selectedProduct.colors?.flatMap((c) => c.images) ||
        [];
      setProductImages(existingImages);
    }
  }, [selectedProduct, form]);

  useEffect(() => {
    if (Array.isArray(imgState) && imgState.length > 0) {
      setProductImages((prevImages) => [...prevImages, ...imgState]);
    }
  }, [imgState]);

  useEffect(() => {
    if (isSuccess && productMessage === "Product Updated Successfully!") {
      toast.success("Manuscript Calibration Successful");
      navigate("/admin/list-product");
    }
    if (isError) {
      toast.error("Calibration Collision Detected");
    }
  }, [isSuccess, isError, productMessage, navigate]);

  const { getRootProps, getInputProps } = useDropzone({
    accept: { "image/*": [".jpeg", ".jpg", ".png"] },
    onDrop: (acceptedFiles) => {
      dispatch(uploadImg(acceptedFiles));
    },
  });

  const handleImageDelete = (public_id) => {
    dispatch(delImg(public_id));
    setProductImages(
      productImages.filter((img) => img.public_id !== public_id),
    );
  };

  const onFinish = (values) => {
    const finalProductData = {
      ...values,
      images: productImages,
    };
    const productData = { id, productData: finalProductData };
    dispatch(updateAProduct(productData));
  };

  // Explicitly defining toast as window notice or importing
  const toast = {
    success: (msg) => console.log("SUCCESS:", msg),
    error: (msg) => console.error("ERROR:", msg),
  };

  const selectedCategory = Form.useWatch("category", form);

  return (
    <div className="space-y-10 pb-20 animate-in fade-in duration-700">
      
      {/* Dynamic Command Header */}
      <div className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-8 bg-white/50 backdrop-blur-xl p-8 rounded-[40px] border border-slate-100 shadow-sm sticky top-0 z-50">
        <div className="space-y-2">
          <div className="flex items-center gap-3 mb-2">
            <span className="flex h-2 w-2 rounded-full bg-blue-600 animate-pulse" />
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-[0.2em] bg-blue-50 px-3 py-1 rounded-full border border-blue-100/50">
              Revision Node v2.1
            </span>
          </div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight flex items-center gap-4">
            Manuscript Calibration
            <span className="h-2 w-2 bg-blue-600 rounded-full" />
          </h1>
          <p className="text-[15px] text-slate-400 font-bold flex items-center gap-2">
            <Cpu size={16} className="text-blue-500" />
            Registry: {id?.slice(-8).toUpperCase()} • Analyzing historical specs.
          </p>
        </div>
        
        <div className="flex items-center gap-4 w-full xl:w-auto">
          <Button
            onClick={() => navigate(-1)}
            icon={<ArrowLeft size={18} />}
            className="flex-1 xl:flex-none h-14 rounded-2xl font-black uppercase text-[11px] tracking-widest border-slate-200 text-slate-500 hover:text-slate-900 hover:bg-slate-50 transition-all flex items-center justify-center gap-3 px-8"
          >
            Abort Revision
          </Button>
          <Button
            onClick={() => form.submit()}
            icon={<Save size={18} />}
            loading={isLoading}
            className="flex-1 xl:flex-none h-14 rounded-2xl font-black uppercase text-[11px] tracking-widest bg-blue-600 text-white border-none px-12 hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/30 flex items-center justify-center gap-3"
          >
            Commit Changes
          </Button>
        </div>
      </div>

      <Spin spinning={isLoading} tip="Syncing Pulse Core Registry...">
        <Form
          form={form}
          layout="vertical"
          onFinish={onFinish}
          className="grid grid-cols-1 xl:grid-cols-4 gap-10"
        >
          {/* Main Workspace Node */}
          <div className="xl:col-span-3 space-y-10">
            
            {/* Identity Card */}
            <div className="bg-white rounded-[40px] border border-slate-100 shadow-2xl shadow-slate-200/40 overflow-hidden group">
               <div className="px-12 py-10 border-b border-slate-50 flex items-center justify-between bg-slate-50/30">
                  <div className="flex items-center gap-6">
                    <div className="w-14 h-14 rounded-2xl bg-blue-600 text-white flex items-center justify-center shadow-lg shadow-blue-600/30 group-hover:rotate-6 transition-transform">
                      <ShoppingBag size={24} />
                    </div>
                    <div>
                      <h3 className="text-[20px] font-black text-slate-900 leading-none">Core Identity</h3>
                      <p className="text-[13px] text-slate-400 font-bold mt-2 uppercase tracking-widest">Base Metadata Level 1</p>
                    </div>
                  </div>
                  <Tag className="bg-emerald-50 text-emerald-600 border-emerald-100 rounded-full font-black text-[10px] uppercase px-4 py-1">Verified Audit</Tag>
               </div>
               
               <div className="p-12 space-y-10">
                  <Form.Item
                    name="title"
                    className="mb-0"
                    label={<span className="text-[12px] font-black text-slate-500 uppercase tracking-widest pl-1">Primary Designation</span>}
                    rules={[{ required: true, message: "Designation ID required" }]}
                  >
                    <Input
                      className="h-16 px-8 rounded-2xl border-slate-100 bg-slate-50/50 focus:bg-white text-[18px] font-black text-slate-900"
                      placeholder="Asset Title..."
                    />
                  </Form.Item>

                  <Form.Item
                    name="description"
                    className="mb-0"
                    label={<span className="text-[12px] font-black text-slate-500 uppercase tracking-widest pl-1">Biological/Clinical Specs</span>}
                    rules={[{ required: true, message: "Specifications required" }]}
                  >
                    <div className="rounded-[32px] overflow-hidden border border-slate-100 bg-slate-50/30">
                      <ReactQuill theme="snow" className="edit-quill-premium" />
                    </div>
                  </Form.Item>
               </div>
            </div>

            {/* Assets Management Node */}
            <div className="bg-white rounded-[40px] border border-slate-100 shadow-2xl shadow-slate-200/40 overflow-hidden">
               <div className="px-12 py-10 border-b border-slate-50 flex items-center gap-6 bg-slate-50/30">
                  <div className="w-14 h-14 rounded-2xl bg-indigo-600 text-white flex items-center justify-center shadow-lg shadow-indigo-600/30 group-hover:-rotate-6 transition-transform">
                    <ImageIcon size={24} />
                  </div>
                  <div>
                    <h3 className="text-[20px] font-black text-slate-900 leading-none">Visual Asset Vault</h3>
                    <p className="text-[13px] text-slate-400 font-bold mt-2 uppercase tracking-widest">Multi-Channel Image Sync</p>
                  </div>
               </div>
               
               <div className="p-12 space-y-12">
                  <div
                    {...getRootProps()}
                    className="border-2 border-dashed border-slate-100 rounded-[40px] p-20 flex flex-col items-center justify-center cursor-pointer hover:border-indigo-400 hover:bg-indigo-50/30 transition-all text-center group/drop bg-slate-50/30"
                  >
                    <input {...getInputProps()} />
                    <div className="w-20 h-20 bg-white rounded-3xl shadow-xl border border-slate-100 flex items-center justify-center mb-8 group-hover/drop:scale-110 group-hover/drop:rotate-12 transition-all duration-500">
                      <Upload size={32} className="text-indigo-600" />
                    </div>
                    <p className="text-[22px] font-black text-slate-900 mb-2">Ingest New Assets</p>
                    <p className="text-[13px] text-slate-400 font-bold uppercase tracking-[0.3em]">SECURE CHANNEL • AUTO-SYNC</p>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-6">
                    {productImages?.map((image, index) => (
                      <div
                        key={index}
                        className="relative group aspect-square rounded-[24px] overflow-hidden border border-slate-100 shadow-lg ring-4 ring-white"
                      >
                        <img
                          src={image.secure_url}
                          alt=""
                          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                        />
                        <button
                          type="button"
                          onClick={() => handleImageDelete(image.public_id)}
                          className="absolute top-3 right-3 w-10 h-10 bg-white/95 backdrop-blur-md text-rose-600 rounded-xl opacity-0 group-hover:opacity-100 transition-all shadow-xl hover:bg-rose-50 flex items-center justify-center"
                        >
                          <X size={20} strokeWidth={3} />
                        </button>
                      </div>
                    ))}
                  </div>
               </div>
            </div>
          </div>

          {/* Configuration Node */}
          <div className="space-y-10">
            
            {/* Segment Selector Card */}
            <div className="bg-white rounded-[40px] border border-slate-100 shadow-2xl shadow-slate-200/40 overflow-hidden">
               <div className="px-10 py-8 border-b border-slate-50 flex items-center gap-4 bg-slate-50/30">
                  <div className="w-12 h-12 rounded-2xl bg-emerald-600 text-white flex items-center justify-center shadow-lg shadow-emerald-600/30">
                    <Layers size={21} />
                  </div>
                  <h3 className="text-[18px] font-black text-slate-900 leading-none">Taxonomy</h3>
               </div>
               
               <div className="p-10 space-y-10">
                  <div className="space-y-5">
                    <label className="text-[12px] font-black text-slate-400 uppercase tracking-widest pl-1">Primary Department</label>
                    <div className="grid grid-cols-1 gap-3">
                       {categoryState?.map((cat, index) => (
                         <button
                           key={index}
                           type="button"
                           onClick={() => form.setFieldValue("category", cat.title)}
                           className={`relative group h-16 rounded-[24px] border transition-all flex items-center px-6 gap-4 overflow-hidden ${
                             selectedCategory === cat.title 
                             ? "border-blue-600 bg-blue-50/50 ring-4 ring-blue-500/10" 
                             : "border-slate-100 bg-white hover:border-blue-200 hover:bg-slate-50/30"
                           }`}
                         >
                           <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${
                             selectedCategory === cat.title ? "bg-blue-600 text-white" : "bg-slate-50 text-slate-400 group-hover:bg-blue-100 group-hover:text-blue-600"
                           }`}>
                              <Box size={18} />
                           </div>
                           <span className={`text-[12px] font-black uppercase tracking-tight ${selectedCategory === cat.title ? "text-blue-700" : "text-slate-600"}`}>
                             {cat.title}
                           </span>
                           {selectedCategory === cat.title && (
                             <div className="ml-auto animate-in zoom-in-50">
                               <CheckCircle2 size={18} className="text-blue-600" />
                             </div>
                           )}
                         </button>
                       ))}
                    </div>
                  </div>

                  <div className="pt-6 border-t border-slate-50 space-y-6">
                    <Form.Item
                      name="brand"
                      label={<span className="text-[12px] font-black text-slate-400 uppercase tracking-widest pl-1">Origin Node</span>}
                    >
                      <Select className="h-16 premium-edit-select" placeholder="Select Brand Agent">
                        {brandState.map((brand) => (
                          <Select.Option key={brand._id} value={brand.title}>
                            <span className="font-black text-[13px] uppercase tracking-wide">{brand.title}</span>
                          </Select.Option>
                        ))}
                      </Select>
                    </Form.Item>
                  </div>
               </div>
            </div>

            {/* Financials & Stock Card */}
            <div className="bg-white rounded-[40px] border border-slate-100 shadow-2xl shadow-slate-200/40 p-10 space-y-8">
               <div className="flex items-center gap-4 mb-2">
                 <div className="w-12 h-12 rounded-2xl bg-blue-50 text-blue-600 flex items-center justify-center">
                    <DollarSign size={20} />
                 </div>
                 <h3 className="text-[18px] font-black text-slate-900 leading-none">Logistics</h3>
               </div>

               <Form.Item
                  name="price"
                  label={<span className="text-[12px] font-black text-slate-400 uppercase tracking-widest pl-1">Market Value (ETB)</span>}
                  rules={[{ required: true, message: "Valuation required" }]}
                >
                  <InputNumber className="w-full h-16 premium-input-num-redesign font-black" />
                </Form.Item>

                <Form.Item
                  name="quantity"
                  label={<span className="text-[12px] font-black text-slate-400 uppercase tracking-widest pl-1">Inventory Load</span>}
                  rules={[{ required: true, message: "Unit count required" }]}
                >
                  <InputNumber className="w-full h-16 premium-input-num-redesign font-black" />
                </Form.Item>

                <Form.Item
                  name="tags"
                  label={<span className="text-[12px] font-black text-slate-400 uppercase tracking-widest pl-1">Global Semantic Tags</span>}
                >
                  <Select mode="tags" className="premium-edit-select" placeholder="Keyword Indexes" />
                </Form.Item>
            </div>

            {/* Protocol notice */}
            <div className="bg-slate-900 rounded-[40px] p-12 text-white relative overflow-hidden group border border-white/5 shadow-2xl">
               <div className="absolute top-0 right-0 p-12 opacity-5 group-hover:scale-110 transition-transform duration-1000 rotate-12">
                  <ShieldCheck size={200} />
               </div>
               <div className="relative z-10 space-y-8">
                  <div className="w-14 h-14 bg-blue-600 rounded-3xl flex items-center justify-center shadow-lg">
                     <Activity size={24} className="text-white" />
                  </div>
                  <div className="space-y-3">
                     <h4 className="text-[20px] font-black uppercase tracking-tight">Integrity Policy</h4>
                     <p className="text-[13px] text-slate-400 font-bold leading-relaxed">
                        Data revisions are tracked via the Pulse Global Ledger. Unauthorized tampering results in audit failure.
                     </p>
                  </div>
                  <button className="w-full h-14 bg-white text-slate-900 rounded-2xl font-black uppercase text-[11px] tracking-widest hover:bg-blue-400 transition-all">
                     Audit History
                  </button>
               </div>
            </div>
          </div>
        </Form>
      </Spin>

      <style>{`
        .edit-quill-premium { border: none !important; }
        .edit-quill-premium .ql-toolbar {
          border: none !important;
          border-bottom: 1px solid #f1f5f9 !important;
          background: #fbfcfd !important;
          padding: 24px !important;
          border-radius: 32px 32px 0 0 !important;
        }
        .edit-quill-premium .ql-container {
          border: none !important;
          min-height: 400px !important;
          padding: 32px !important;
          font-size: 16px !important;
          background: #fff !important;
          border-radius: 0 0 32px 32px !important;
        }
        .edit-quill-premium .ql-editor { font-family: 'Outfit', sans-serif !important; font-weight: 500 !important; color: #1e293b !important; line-height: 1.8 !important; }
        
        .premium-edit-select .ant-select-selector {
          background: #f8fafc !important;
          border-radius: 20px !important;
          border: 1px solid #f1f5f9 !important;
          padding: 0 24px !important;
          height: 64px !important;
          display: flex !important;
          align-items: center !important;
        }
        
        .premium-input-num-redesign {
          background: #f8fafc !important;
          border-radius: 20px !important;
          border: 1px solid #f1f5f9 !important;
          display: flex !important;
          align-items: center !important;
          font-size: 18px !important;
        }
        
        .premium-input-num-redesign .ant-input-number-input {
          height: 64px !important;
          padding: 0 24px !important;
        }

        .ant-form-item-label label {
          margin-bottom: 8px !important;
        }
      `}</style>
    </div>
  );
};

export default EditProducts;
